import React, { useState, useEffect } from "react";
import axios from "axios";

// Configuración de la URL base (usa localhost si no hay variable de entorno)
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [productoActual, setProductoActual] = useState({
    ProductoID: null,
    Nombre: "",
    Descripcion: "",
    Precio: "",
    Stock: "",
    CategoriaID: "",
    Imagen: null,
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  // Estados para modal de imagen y animaciones
  const [imagenModal, setImagenModal] = useState(null);
  const [animarModal, setAnimarModal] = useState(false);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 7;

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      const [resProd, resCat] = await Promise.all([
        axios.get(`${API_URL}/api/productos`),
        axios.get(`${API_URL}/api/categorias`)
      ]);

      setProductos(resProd.data);
      // Mapeamos las categorías de Postgres (id/nombre) a la estructura del componente
      setCategorias(resCat.data.map(c => ({
        CategoriaID: c.id,
        Nombre: c.nombre
      })));
    } catch (error) {
      console.error("❌ Error al cargar datos:", error);
    }
  };

  const handleChange = (e) => {
    setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setProductoActual({ ...productoActual, Imagen: e.target.files[0] });
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      ProductoID: null,
      Nombre: "",
      Descripcion: "",
      Precio: "",
      Stock: "",
      CategoriaID: "",
      Imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (p) => {
    setProductoActual({
      ProductoID: p.ProductoID,
      Nombre: p.Nombre,
      Descripcion: p.Descripcion,
      Precio: p.Precio,
      Stock: p.Stock,
      CategoriaID: p.CategoriaID || p.categoria_id,
      Imagen: null, 
    });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append("Nombre", productoActual.Nombre);
    formData.append("Descripcion", productoActual.Descripcion);
    formData.append("Precio", productoActual.Precio);
    formData.append("Stock", productoActual.Stock);
    formData.append("categoria_id", productoActual.CategoriaID);
    
    if (productoActual.Imagen) {
      formData.append("Imagen", productoActual.Imagen);
    }

    try {
      const config = { headers: { "Content-Type": "multipart/form-data" } };
      
      if (modoEdicion) {
        await axios.put(`${API_URL}/api/productos/${productoActual.ProductoID}`, formData, config);
      } else {
        await axios.post(`${API_URL}/api/productos`, formData, config);
      }
      
      setShowModal(false);
      cargarDatos();
    } catch (error) {
      alert("Error al guardar producto");
      console.error(error);
    }
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`${API_URL}/api/productos/${id}`);
        cargarDatos();
      } catch (error) {
        console.error("❌ Error al eliminar:", error);
      }
    }
  };

  // Lógica de búsqueda
  const productosFiltrados = productos.filter((p) => {
    const term = busqueda.toLowerCase();
    return (
      (p.Nombre?.toLowerCase() || "").includes(term) ||
      (p.Descripcion?.toLowerCase() || "").includes(term)
    );
  });

  // Lógica de paginación
  const totalPaginas = Math.ceil(productosFiltrados.length / productosPorPagina);
  const productosPaginados = productosFiltrados.slice(
    (paginaActual - 1) * productosPorPagina,
    paginaActual * productosPorPagina
  );

  return (
    <div className="container mt-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          placeholder="Buscar producto..."
          className="form-control w-50"
          value={busqueda}
          onChange={(e) => { setBusqueda(e.target.value); setPaginaActual(1); }}
        />
        <button className="btn btn-success" onClick={abrirModalAgregar}>
          ➕ Nuevo Producto
        </button>
      </div>

      <div className="table-responsive shadow-sm bg-white rounded">
        <table className="table table-hover text-center align-middle mb-0">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Imagen</th>
              <th>Nombre</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productosPaginados.map((p) => (
              <tr key={p.ProductoID}>
                <td>{p.ProductoID}</td>
                <td>
                  {p.Imagen ? (
                    <img
                      src={`${API_URL}/uploads/${p.Imagen}`}
                      alt={p.Nombre}
                      className="rounded shadow-sm"
                      style={{ width: "50px", height: "50px", objectFit: "cover", cursor: "pointer" }}
                      onClick={() => { setImagenModal(p.Imagen); setAnimarModal(true); }}
                    />
                  ) : <span className="text-muted">Sin foto</span>}
                </td>
                <td className="fw-bold">{p.Nombre}</td>
                <td>${parseFloat(p.Precio).toFixed(2)}</td>
                <td>
                    <span className={`badge ${p.Stock < 5 ? 'bg-danger' : 'bg-primary'}`}>
                        {p.Stock} unidades
                    </span>
                </td>
                <td>
                  <button className="btn btn-outline-warning btn-sm me-2" onClick={() => abrirModalEditar(p)}>✏️</button>
                  <button className="btn btn-outline-danger btn-sm" onClick={() => eliminarProducto(p.ProductoID)}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Paginador */}
      <nav className="mt-4">
        <ul className="pagination justify-content-center">
          {Array.from({ length: totalPaginas }, (_, i) => (
            <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
              <button className="page-link" onClick={() => setPaginaActual(i + 1)}>{i + 1}</button>
            </li>
          ))}
        </ul>
      </nav>

      {/* MODAL CREAR/EDITAR */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog modal-lg">
            <div className="modal-content shadow-lg border-0">
              <div className="modal-header bg-primary text-white">
                <h5 className="modal-title">{modoEdicion ? "Editar Producto" : "Nuevo Producto"}</h5>
                <button className="btn-close btn-close-white" onClick={() => setShowModal(false)}></button>
              </div>
              <form onSubmit={guardarProducto}>
                <div className="modal-body p-4">
                  <div className="row g-3">
                    <div className="col-md-6">
                      <label className="form-label fw-bold">Nombre</label>
                      <input type="text" name="Nombre" value={productoActual.Nombre} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold">Precio</label>
                      <input type="number" step="0.01" name="Precio" value={productoActual.Precio} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold">Stock</label>
                      <input type="number" name="Stock" value={productoActual.Stock} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold">Categoría</label>
                      <select name="CategoriaID" value={productoActual.CategoriaID} onChange={handleChange} className="form-select" required>
                        <option value="">Seleccione...</option>
                        {categorias.map(c => <option key={c.CategoriaID} value={c.CategoriaID}>{c.Nombre}</option>)}
                      </select>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold">Descripción</label>
                      <textarea name="Descripcion" value={productoActual.Descripcion} onChange={handleChange} className="form-control" rows="2"></textarea>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold">Imagen</label>
                      <input type="file" className="form-control" onChange={handleFileChange} />
                    </div>
                  </div>
                </div>
                <div className="modal-footer bg-light">
                  <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Cerrar</button>
                  <button type="submit" className="btn btn-primary">Guardar Cambios</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* MODAL ZOOM IMAGEN */}
      {imagenModal && (
        <div className={`modal fade show d-flex align-items-center justify-content-center`} 
             style={{ backgroundColor: "rgba(0,0,0,0.9)", position: "fixed", top: 0, left: 0, width: "100%", height: "100%", zIndex: 2000, opacity: animarModal ? 1 : 0, transition: '0.3s' }}
             onClick={() => { setAnimarModal(false); setTimeout(() => setImagenModal(null), 300); }}>
          <img src={`${API_URL}/uploads/${imagenModal}`} alt="Zoom" className="img-fluid rounded" style={{ maxHeight: "90vh", transform: animarModal ? 'scale(1)' : 'scale(0.8)', transition: '0.3s' }} />
        </div>
      )}
    </div>
  );
}
